previewCss:
.darma-loader-darma-custom-128 {
  color: #0f766e;
width: 49px;
aspect-ratio: .75;
--c:no-repeat linear-gradient(135deg,currentColor,var(--loader-secondary-color));
background:
var(--c) 0% 100%,
var(--c) 50% 100%,
var(--c) 100% 100%;
background-size: 20% 65%;
animation: darma-loader-darma-custom-128-l8 1s infinite linear;
}
@keyframes darma-loader-darma-custom-128-l8 {
16.67% {background-position: 0% 0% ,50% 100%,100% 100%}
33.33% {background-position: 0% 0% ,50% 0% ,100% 100%}
50% {background-position: 0% 0% ,50% 0% ,100% 0% }
66.67% {background-position: 0% 100%,50% 0% ,100% 0% }
83.33% {background-position: 0% 100%,50% 100%,100% 0% }
}

